import React from "react";

const About = ({ data }) => {
  return (
    <section className="developers-section-wrapper item-center gap-md">
      <div className="item-center c-gap">
        <span className="gradient-badge-v2">{data.badgeText}</span>
        <div className="item-center gap-sm">
          <h2 className="about-h2 font-black ">{data.title}</h2>
          <p className="about-p-two light-gray c-text-center">
            {data.description}
          </p>
        </div>
      </div>
      <ul className="developers-about-cards c-grid grid-three gap-md">
        {data.boxData.map((item, idx) => (
          <li className="developers-about-card flex-center gap-sm" key={idx}>
            <div className="dot"></div>
            <p className="about-p-two font-black">{item.title}</p>
          </li>
        ))}
      </ul>
    </section>
  );
};

export default About;
