import React from "react";
import fllledStar from "@styles/assets/images/hire-devs/filledstar.svg";
import unFllledStar from "@styles/assets/images/hire-devs/unfilledstar.svg";
import quotes from "@images/hirescreens/devPages/icons/quotes.png";

const Reviews = ({ data }) => {
  const totalStars = 5;

  return (
    <section className="developers-section-wrapper item-center gap-xl">
      <div className="item-center gap-sm">
        <h2 className="about-h2 font-black">{data.title}</h2>
        <p className="about-p-two light-gray">{data.description}</p>
      </div>
      <div className="developer-review-cards c-grid grid-three w-100">
        {data.boxData.map((item, idx) => (
          <div className="developer-review-card item-start gap-xl" key={idx}>
            <div className="item-start gap-sm">
              <img src={quotes} alt="quotes" />
              <div>
                {[...Array(totalStars)].map((_, index) => (
                  <img
                    key={index}
                    src={index < item.rating ? fllledStar : unFllledStar}
                    alt={index < item.rating ? "filled star" : "unfilled star"}
                  />
                ))}
              </div>
              <p className="about-p-two light-gray">{item.review}</p>
            </div>
            <p className="about-p font-black fw-600 ">-{item.name}</p>
          </div>
        ))}
      </div>
    </section>
  );
};

export default Reviews;
