import React from "react";
import card_cross_box from "@images/hirescreens/devPages/card-cross-box.svg";
const OurService = ({ data }) => {
  return (
    <section className="developers-section-wrapper sticky-wrapper flex gap-xl">
      <div className="item-start developer-service-sticky gap-lg">
        <span className="gradient-badge-v2">{data.badgeText}</span>
        <div className="item-start gap-sm">
          <h2 className="about-h2 font-black ">{data.title}</h2>
          <p className="about-p-two light-gray">{data.description}</p>
        </div>
      </div>
      <div className="developer-service-content flex-column gap-lg">
        {data.boxData.map((item, idx) => (
          <div className="developer-service-card item-start gap-2" key={idx}>
            <img src={card_cross_box} alt={item.title} />
            <div className="developer-service-card-content item-start gap-4">
              <p className="about-p-two font-black fw-600">{item.title}</p>
              <p className="about-p-two light-gray">{item.desc}</p>
            </div>
          </div>
        ))}
      </div>
    </section>
  );
};

export default OurService;
