import About from "./About";
import Achieves from "./Achieves";
import Hero from "./Hero";
import OurService from "./OurService";
import "./style.css";
import React from "react";
import Techs from "./Techs";
import WhyChooseUs from "./WhyChooseUs";
import DevProcess from "./DevProcess";
import OurExperts from "./OurExperts";
import Reviews from "./Reviews";
import HireFaq from "./HireFaq";

const HireDeveloper = (props) => {
  const { db, data } = props;
  return (
    <div>
      <Hero db={db} data={data.home} />
      <Achieves data={data.achieves} />
      <About data={data.about} />
      <OurService data={data.ourService} />
      <Techs data={data.ourTechs} />
      <WhyChooseUs data={data.whyChooseUs} />
      <DevProcess data={data.devProcess} />
      <OurExperts data={data.ourExperts} />
      <Reviews data={data.reviews} />
      <HireFaq data={data.faq} />
    </div>
  );
};

export default HireDeveloper;
