import React from "react";
import { GatsbyImage, getImage } from "gatsby-plugin-image";
import TalkToUsNew from "@components/common/talk-to-us-new";
import { Link } from "@reach/router";
import fllledStar from "@styles/assets/images/hire-devs/filledstar.svg";
import unFllledStar from "@styles/assets/images/hire-devs/unfilledstar.svg";

const Hero = ({ db, data }) => {
  const imageData = getImage(data.image);
  const totalStars = 5;
  const rating = Number(data.review);
  const filledStar = fllledStar;
  const unfilledStar = unFllledStar;

  return (
    <section className="developers-section-wrapper flex-center md-flex-column gap-xl">
      <div className="item-start gap-lg w-full">
        <div className="item-start gap-sm">
          <span className="developers-tag about-p"># {data.tag}</span>
          <div className="flex-center developers-review-star">
            {[...Array(totalStars)].map((_, index) => (
              <img
                key={index}
                src={index < rating ? filledStar : unfilledStar}
                alt="star"
              />
            ))}
            <p className="about-p-three">{data.review}/5 reviews</p>
          </div>
        </div>
        <h1 className="about-h2-v2 font-black font-black">{data.title}</h1>
        <p className="about-p font-black">{data.description}</p>
        <div className="buttons">
          <Link to="/contact-us" className="roll-button roll-btn">
            <span>Hire Now</span>
          </Link>
          <TalkToUsNew
            db={db}
            label="Free Consultation"
            customClass="normal-roll-button normal-roll-btn"
          />
        </div>
      </div>
      <div className="hire-dev-hero-image">
        <GatsbyImage
          image={imageData}
          alt={data.imageAlt || data.title}
          loading="eager"
          placeholder="none"
          fetchpriority="high"
        />
      </div>
    </section>
  );
};

export default Hero;
