import React from "react";

const DevProcess = ({ data }) => {
  return (
    <section className="developers-section-wrapper item-center gap-2xl">
      <div className="item-center c-gap">
        <span className="gradient-badge-v2">{data.badgeText}</span>
        <h2 className="about-h2 font-black ">{data.title}</h2>
      </div>
      <div className="developer-process-cards c-grid grid-four">
        {data.boxData.map((item, idx) => (
          <div className="developer-process-card item-center gap-sm" key={idx}>
            <div className="developer-process-icon-frame">
              <img src={item.icon} alt={item.title} width={40} height={40} />
            </div>
            <span className="developer-process-icon-two-frame about-p-two">
              0{item.id}
            </span>
            <p className="about-p-two font-black fw-600">{item.title}</p>
          </div>
        ))}
      </div>
    </section>
  );
};

export default DevProcess;
