import React from "react";

const Achieves = ({ data }) => {
  return (
    <section className="developers-achieves-section-wrapper">
      <div className="developers-achieves-outer-cards-section">
        <div className="developers-achieves-cards-section c-grid grid-four gap-md">
          {data.boxData.map((item) => (
            <div
              key={item.id}
              className="developers-achieves-card item-center gap-2"
            >
              <span className="about-h4 font-white">
                {item.number}
                {item.isPercentage ? "%" : "+"}
              </span>
              <p className="about-p-two font-white">{item.title}</p>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Achieves;
