import React from "react";

const OurExperts = ({ data }) => {
  return (
    <section className="developers-section-wrapper item-center gap-2xl">
      <div className="item-center c-gap">
        <span className="gradient-badge-v2">{data.badgeText}</span>
        <h2 className="about-h2 font-black ">{data.title}</h2>
      </div>
      <div className="developer-expert-cards c-grid grid-four w-100">
        {data.boxData.map((item, idx) => (
          <div className="developer-expert-card flex-center" key={idx}>
            <img src={item.icon} alt={item.title} />
            <p className="about-p-two font-black fw-600 ">{item.title}</p>
          </div>
        ))}
      </div>
    </section>
  );
};

export default OurExperts;
