import React from "react";

const WhyChooseUs = ({ data }) => {
  return (
    <section className="developer-choose-container">
      <section className="developers-section-wrapper item-center gap-2xl">
        <div className="item-center gap-lg">
          <span className="gradient-badge-v2">{data.badgeText}</span>
          <div className="item-center gap-sm">
            <h2 className="about-h2 font-black ">{data.title}</h2>
            <p className="about-p-two light-gray">{data.description}</p>
          </div>
        </div>
        <div className="developer-choose-cards c-grid grid-three gap-lg w-100">
          {data.boxData.map((item, idx) => (
            <div className="developer-choose-card item-start" key={idx}>
              <div className="developer-choose-icon-frame">
                <img src={item.icon} alt={item.title} />
              </div>
              <p className="about-p font-black fw-600">{item.title}</p>
              <p className="about-p-three font-black">{item.desc}</p>
            </div>
          ))}
        </div>
      </section>
    </section>
  );
};

export default WhyChooseUs;
